import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'Sunny',
    humidity = 0,
    windSpeed = 0,
    unit = '°C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={16}>
        {/* Main Weather Header */}
        <Stack gap={4}>
          <Heading level={2}>{city}</Heading>
          <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
            {condition}
          </Text>
        </Stack>

        {/* Current Metrics */}
        <Stack direction="horizontal" justify="between" align="center">
          <Text size="4xl" weight="bold">
            {temperature}
            {unit}
          </Text>
          <Stack gap={4}>
            <Text variant="bodySmall">
              Humidity: <strong>{humidity}%</strong>
            </Text>
            <Text variant="bodySmall">
              Wind: <strong>{windSpeed} km/h</strong>
            </Text>
          </Stack>
        </Stack>

        <Divider margin={8} />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <Stack key={index} gap={4} align="center">
              <Text variant="overline">{item.day ?? '-'}</Text>
              <Text size="2xl">{item.icon ?? '☀️'}</Text>
              <Stack direction="horizontal" gap={4}>
                <Text size="sm" weight="semibold">
                  {item.high ?? 0}°
                </Text>
                <Text size="sm" color="var(--ggui-color-neutral-500, #6b7280)">
                  {item.low ?? 0}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}
